import React from "react";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from "recharts";

export default function BusCharts({ buses }) {
  const data = [
    {
      name: "Buses",
      Running: buses.filter((b) => b.status === "Running").length,
      Ghost: buses.filter((b) => b.status === "Ghost").length,
      Anomaly: buses.filter((b) => b.status === "Anomaly").length,
    },
  ];

  return (
    <div style={{ width: 300, height: 200, position: "absolute", top: 60, left: 50, zIndex: 1000, background: "white", padding: "10px", borderRadius: "8px", boxShadow: "0 2px 6px rgba(0,0,0,0.2)" }}>
      <ResponsiveContainer width="100%" height="100%">
        <BarChart data={data}>
          <XAxis dataKey="name" />
          <YAxis />
          <Tooltip />
          <Legend />
          <Bar dataKey="Running" fill="green" />
          <Bar dataKey="Ghost" fill="red" />
          <Bar dataKey="Anomaly" fill="orange" />
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
}
